<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __be16          ar_hrd;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         /* 硬件地址格式 (Hardware type)          */</span></span>
